<div class="d-flex justify-content-between align-items-center mb-4"><div><p class="text-uppercase fw-semibold archive-kicker-dark mb-1">Trust & safety</p><h1 class="h2 mb-0">Moderation Reports</h1></div><a class="btn btn-outline-secondary" href="<?= e(url('/admin')) ?>">Dashboard</a></div>
<?php if ($reports === []): ?><div class="archive-card p-4 text-muted">No reports submitted.</div><?php else: ?>
<div class="row g-3"><?php foreach ($reports as $report): ?><div class="col-12"><div class="archive-card p-3"><div class="row g-3">
    <div class="col-lg-7"><div class="d-flex gap-2 align-items-center"><strong>Report #<?= e((string) $report['id']) ?></strong><span class="badge text-bg-light"><?= e($report['status']) ?></span></div><div class="small text-muted">Reporter: <?= e($report['reporter_username']) ?> · <?= e($report['subject_type']) ?>: <?= e($report['subject_label'] ?: '#' . $report['subject_id']) ?> · <?= e($report['created_at']) ?></div><div class="mt-2"><strong><?= e(ucwords(str_replace('_',' ', $report['reason']))) ?></strong></div><div><?= nl2br(e($report['details'])) ?></div></div>
    <div class="col-lg-5"><form method="post" action="<?= e(url('/admin/reports/status?id=' . (int) $report['id'])) ?>"><label class="form-label small">Status</label><select class="form-select form-select-sm mb-2" name="status"><?php foreach (['open','reviewing','resolved','dismissed'] as $status): ?><option value="<?= e($status) ?>" <?= $report['status'] === $status ? 'selected' : '' ?>><?= e(ucfirst($status)) ?></option><?php endforeach; ?></select><label class="form-label small">Resolution notes</label><textarea class="form-control form-control-sm" name="resolution_notes" maxlength="2000" rows="3"><?= e($report['resolution_notes'] ?? '') ?></textarea><button class="btn btn-sm btn-archive mt-2">Save review</button></form></div>
</div></div></div><?php endforeach; ?></div><?php endif; ?>
